import{C as t,o,c as n,a5 as a,E as l}from"./chunks/framework.CW28V7p_.js";const c=JSON.parse('{"title":"1. Proof of History (PoH)","description":"","frontmatter":{},"headers":[],"relativePath":"module-4/1-poh.md","filePath":"module-4/1-poh.md","lastUpdated":1780937944000}'),r={name:"module-4/1-poh.md"},k=Object.assign(r,{setup(h){const e={id:"m4-1-poh",title:"🧠 Mini-check: Proof of History",intro:"3 питання — PoH fundamentals.",questions:[{type:"explain",q:"Поясни своїми словами що таке PoH і чому Solana її потребує.",ideal:`PoH (Proof of History) — це децентралізований "годинник", який доводить що passing time через recursive SHA-256 hashing. Validator continuously обчислює hash(previous_hash) у loop, кожна iteration triggers "tick". Скільки ticks = скільки часу пройшло (з deterministic перерахунком per ticks per second).

Чому Solana потребує:

1. Без trusted clock — нема способу validators agree про порядок подій. PoH дає cryptographically verifiable timeline без trust.

2. Enables 400ms slots: leader може швидко вкладати TXs у "поточне" time window (current PoH tick range), без чекати global gossip про "котра година".

3. Permits fast Tower BFT consensus: validators використовують PoH timestamps щоб verify когда vote was issued, прискорюючи tower computation.

4. Reduces network overhead: не треба broadcast "сurrent time" з кожним message — PoH sequence sами self-проявляє time.

Аналогія: SHA-256 hashing як stopwatch — кожен click того ж самого хімічного механізму doves одиниця часу пройшла, тому що SHA є computationally expensive (потрібен real CPU work). Не можна fake "I did 1000 hashes" без реально їх обчислення.`,explanation:"Ключове: cryptographic clock без trust, enabler fast consensus. Якщо описала hashing loop + чому це matter — повна відповідь."},{type:"mcq",q:"Що з цього вірно про PoH? (обери всі)",options:["PoH тільки leader обчислює, не cluster","PoH не consensus per se — це timestamping mechanism","PoH ticks deterministic — different validators verifying same sequence reach same conclusions","PoH замінює Tower BFT як voting consensus"],correct:[0,1,2],explanation:"PoH — це clock, не voting consensus (Tower BFT робить voting). Тільки current leader generates PoH. Other validators verify sequence. Tower BFT та PoH працюють разом. Module 4.1."},{type:"mcq",q:'Що значить "tick" у PoH context?',options:["Single iteration hash(prev_hash) → next_hash","Marker через які passing time можна measure","Group of ~12,500 hashes that produce one PoH counter increment","Vote signal до cluster"],correct:[0,1,2],explanation:"Tick це basic time unit у PoH. На mainnet 1 tick = ~12,500 hashes (~6.25 ticks per slot). Не vote (це Tower BFT). Module 4.1."}]};return(p,s)=>{const i=t("Quiz");return o(),n("div",null,[s[0]||(s[0]=a(`<h1 id="_1-proof-of-history-poh" tabindex="-1">1. Proof of History (PoH) <a class="header-anchor" href="#_1-proof-of-history-poh" aria-label="Permalink to &quot;1. Proof of History (PoH)&quot;">​</a></h1><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p><strong>PoH (Proof of History)</strong> — це cryptographic clock built з recursive SHA-256 hashing. Solana validator (current leader) continuously обчислює <code>hash(previous_hash) → next_hash</code> у loop. Це creates verifiable sequence де кожна iteration proves real CPU time passed.</p><p>PoH <strong>не consensus сам по собі</strong> — це <strong>timestamping mechanism</strong>. Consensus робить Tower BFT (Module 4.2). PoH dає Tower BFT надiйний <code>&quot;котра година&quot;</code> що дозволяє швидке voting.</p><h2 id="концепти" tabindex="-1">Концепти <a class="header-anchor" href="#концепти" aria-label="Permalink to &quot;Концепти&quot;">​</a></h2><h3 id="проблема-time-у-distributed-system" tabindex="-1">Проблема: time у distributed system <a class="header-anchor" href="#проблема-time-у-distributed-system" aria-label="Permalink to &quot;Проблема: time у distributed system&quot;">​</a></h3><p>Класична задача distributed systems — як validators agree про порядок подій без trusted central clock?</p><p>Bitcoin solution: blocks come з timestamp from miner. But miners can lie. So Bitcoin uses block depth (probability of canonical chain) як time approximation.</p><p>Solana solution: <strong>cryptographic clock</strong> через PoH — кожен validator може <strong>independently verify</strong> time passage.</p><h3 id="як-poh-працює" tabindex="-1">Як PoH працює <a class="header-anchor" href="#як-poh-працює" aria-label="Permalink to &quot;Як PoH працює&quot;">​</a></h3><p>Leader continuously runs loop:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>loop {</span></span>
<span class="line"><span>    next_hash = sha256(previous_hash)</span></span>
<span class="line"><span>    previous_hash = next_hash</span></span>
<span class="line"><span>    counter += 1</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    if counter % 12500 == 0 {</span></span>
<span class="line"><span>        emit_tick(counter, current_hash)</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>Each iteration takes <strong>real CPU time</strong> (SHA-256 не зайвий — потрібен compute work). Не можна fake &quot;I did 1M iterations&quot; без actually doing them.</p><p>Periodically (~6.25 рази за 400ms slot, тобто ~64 ticks/sec) leader emits <strong>tick</strong> — marker з counter + hash. Tick = &quot;this much time has passed since last tick&quot;.</p><h3 id="чому-це-це-clock" tabindex="-1">Чому це це clock <a class="header-anchor" href="#чому-це-це-clock" aria-label="Permalink to &quot;Чому це це clock&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Без PoH</th><th>З PoH</th></tr></thead><tbody><tr><td>Validator timestamp = wall clock (можна fake)</td><td>Validator timestamp = PoH position (cryptographically proven)</td></tr><tr><td>Trust source требеба для clock sync</td><td>Trustless: any validator can verify PoH sequence</td></tr><tr><td>Time disagreement → consensus issues</td><td>All validators agree on PoH sequence ↔ time</td></tr></tbody></table><p>PoH дає cluster-wide <strong>monotonic timeline</strong> без trust:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PoH(0) → PoH(1) → PoH(2) → PoH(3) → ...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Кожна стрілка = real CPU work, не можна skip.</span></span>
<span class="line"><span>&quot;Counter at 12500&quot; означає 12500 hashes computed since start.</span></span></code></pre></div><h3 id="poh-не-consensus" tabindex="-1">PoH не consensus <a class="header-anchor" href="#poh-не-consensus" aria-label="Permalink to &quot;PoH не consensus&quot;">​</a></h3><p>Це важливо: <strong>PoH не вирішує &quot;хто має rights to write blocks&quot;</strong> — це Tower BFT job (Module 4.2). PoH just provides <strong>timing infrastructure</strong>.</p><p>Specifically PoH:</p><ul><li>Помагає leader stamp transactions з accurate time (no need для wall clock)</li><li>Allows validators to verify &quot;leader did process TX at PoH tick N&quot;</li><li>Provides timeline для votes (&quot;validator voted at PoH tick M&quot;)</li></ul><p>Tower BFT then uses цю timeline + stake weights для consensus.</p><h3 id="tick-rate-vs-slot-rate" tabindex="-1">Tick rate vs slot rate <a class="header-anchor" href="#tick-rate-vs-slot-rate" aria-label="Permalink to &quot;Tick rate vs slot rate&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Concept</th><th>Rate</th><th>Time</th></tr></thead><tbody><tr><td>Hash</td><td>~6 billion/sec on validator CPU</td><td>sub-nanosecond</td></tr><tr><td>Tick</td><td>~64/sec</td><td>~15.6ms кожен</td></tr><tr><td>Slot</td><td>2.5/sec</td><td>400ms кожен</td></tr></tbody></table><p>Тобто:</p><ul><li>1 slot = 64 ticks</li><li>1 tick = 12500 hashes (mainnet config)</li><li>1 hash = sub-nanosecond</li></ul><p>Leader emits tick кожні 12500 hashes ≈ 15.6ms ≈ 64 ticks per second. Validators verify ticks independently.</p><h3 id="як-validators-verify-poh" tabindex="-1">Як validators verify PoH <a class="header-anchor" href="#як-validators-verify-poh" aria-label="Permalink to &quot;Як validators verify PoH&quot;">​</a></h3><p>Validator receives block з leader. Block contains PoH sequence (ticks + TXs interleaved). Validator:</p><ol><li>Takes starting hash (from previous block)</li><li>Replays sequence: for each tick, compute hash(prev) и compare to leader&#39;s hash</li><li>If matches — sequence valid. Якщо ні — block invalid, reject.</li></ol><p>Verification потребує real CPU time (same compute as generation). Це і безпекова guarantee — fake PoH sequence неможливо without actually doing work.</p><h3 id="poh-leader-vs-poh-validator" tabindex="-1">PoH leader vs PoH validator <a class="header-anchor" href="#poh-leader-vs-poh-validator" aria-label="Permalink to &quot;PoH leader vs PoH validator&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Role</th><th>Compute</th></tr></thead><tbody><tr><td>Leader (in their slot)</td><td>Generates PoH (continuous hashing)</td></tr><tr><td>Non-leader validators</td><td>Verifies received PoH (replay hashing)</td></tr><tr><td>Leader switching slots</td><td>Hands off PoH stream to next leader</td></tr></tbody></table><p>Leader changes every 4 slots (mainnet leader slot groups). PoH stream continuity preserved through handoffs.</p><h3 id="why-poh-critical-для-performance" tabindex="-1">Why PoH critical для performance <a class="header-anchor" href="#why-poh-critical-для-performance" aria-label="Permalink to &quot;Why PoH critical для performance&quot;">​</a></h3><p>Без PoH Solana би потребував traditional consensus protocols (Paxos, Raft, classical BFT) які потребують many rounds messages для agreement. Це slow (multi-second finality).</p><p>З PoH:</p><ul><li>Leader broadcasts block with embedded PoH timeline</li><li>Validators can verify timing without additional gossip messages</li><li>Tower BFT votes can reference PoH positions</li><li>Consensus converges fast (1-3 sec confirmed, 12-30 sec finalized)</li></ul><p>Це key enabler 400ms slots.</p><h2 id="connect-to-your-work" tabindex="-1">Connect to your work <a class="header-anchor" href="#connect-to-your-work" aria-label="Permalink to &quot;Connect to your work&quot;">​</a></h2><h3 id="poh-у-твоєму-validator-workflow" tabindex="-1">PoH у твоєму validator workflow <a class="header-anchor" href="#poh-у-твоєму-validator-workflow" aria-label="Permalink to &quot;PoH у твоєму validator workflow&quot;">​</a></h3><p>Коли твій validator стає leader:</p><ol><li>PoH thread starts hashing (initialized з last block&#39;s PoH)</li><li>Banking stage processes incoming TXs, interleaves them у PoH stream</li><li>Tick markers emit ~64/sec</li><li>На slot end — block contains full PoH sequence</li></ol><p>Якщо твоя CPU <strong>повільна</strong> — PoH generation rate drops → less throughput per slot → fewer TXs included → потенційно skipped slot.</p><p>Це чому validator CPU потребує <strong>high single-thread performance</strong> — PoH single-threaded by design.</p><h3 id="monitoring-poh-performance" tabindex="-1">Monitoring PoH performance <a class="header-anchor" href="#monitoring-poh-performance" aria-label="Permalink to &quot;Monitoring PoH performance&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/solana/solana.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;PoH&quot;</span></span></code></pre></div><p>Common log lines:</p><ul><li><code>PoH tick rate: 6,250,000 hashes/sec</code> — normal</li><li><code>PoH overrun warning</code> — leader не встигає hash → degraded performance</li><li><code>Tick height N</code> — поточна tick</li></ul><p>Якщо overruns frequent → CPU bottleneck.</p><h2 id="hands-on-exercise" tabindex="-1">Hands-on exercise <a class="header-anchor" href="#hands-on-exercise" aria-label="Permalink to &quot;Hands-on exercise&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Подивись poH state локального validator</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag/bin/solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> epoch-info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8899</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;block height&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Block height = number of non-skipped blocks (related но не equal до slot)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Поточна slot vs block height — різниця показує skipped slots count</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">SLOT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag/bin/solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> slot</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8899</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">BLOCK</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/ag/bin/solana</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> epoch-info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --url</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:8899</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Block height&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> awk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{print $3}&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Slot: </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$SLOT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">, Block: </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$BLOCK</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">, Skipped: $((</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">SLOT</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> - BLOCK))&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># PoH logs</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;poh&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/solana/solana/solana.log</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -20</span></span></code></pre></div><h2 id="mini-quiz" tabindex="-1">Mini-quiz <a class="header-anchor" href="#mini-quiz" aria-label="Permalink to &quot;Mini-quiz&quot;">​</a></h2>`,54)),l(i,{data:e}),s[1]||(s[1]=a('<h2 id="glossary-additions" tabindex="-1">Glossary additions <a class="header-anchor" href="#glossary-additions" aria-label="Permalink to &quot;Glossary additions&quot;">​</a></h2><p><a href="/glossary#p"><code>PoH</code></a>, <a href="/glossary#t"><code>Tick</code></a>, <a href="/glossary#s"><code>SHA-256</code></a>, <a href="/glossary#p"><code>PoH leader</code></a>, <a href="/glossary#b"><code>Banking stage</code></a>, <a href="/glossary#p"><code>PoH verifier</code></a></p><h2 id="external-refs" tabindex="-1">External refs <a class="header-anchor" href="#external-refs" aria-label="Permalink to &quot;External refs&quot;">​</a></h2><ul><li><a href="https://docs.anza.xyz/cluster/synchronization" target="_blank" rel="noreferrer">Anza: Proof of History</a></li><li><a href="https://solana.com/solana-whitepaper.pdf" target="_blank" rel="noreferrer">Anatoly Yakovenko: PoH whitepaper</a> — original 2017 paper</li><li><a href="https://www.helius.dev/blog/proof-of-history-proof-of-stake-proof-of-work-explained" target="_blank" rel="noreferrer">Helius: PoH Explained</a></li></ul><hr><p><strong>Наступне:</strong> <a href="/module-4/2-tower-bft">2. Tower BFT →</a></p>',6))])}}});export{c as __pageData,k as default};
